CREATE TABLE accounts (
  account_id INT PRIMARY KEY,
  owner      VARCHAR(50),
  balance    DECIMAL(10,2)
);

INSERT INTO accounts VALUES (1,'Alice',1000),(2,'Bob',800);

-- DEADLOCK SCENARIO (conceptual — cannot truly demo in single script):
-- Transaction A (Session 1):
--   BEGIN;
--   UPDATE accounts SET balance = balance - 100 WHERE account_id = 1;  -- locks row 1
--   -- waits for row 2...
--   UPDATE accounts SET balance = balance + 100 WHERE account_id = 2;
--   COMMIT;

-- Transaction B (Session 2, simultaneously):
--   BEGIN;
--   UPDATE accounts SET balance = balance - 50 WHERE account_id = 2;   -- locks row 2
--   -- waits for row 1... DEADLOCK!
--   UPDATE accounts SET balance = balance + 50 WHERE account_id = 1;
--   COMMIT;

-- PREVENTION: always lock rows in the same order across all transactions
-- Transaction A and B both lock account 1 first, then account 2

-- Safe pattern: always update lower account_id first
BEGIN;
  UPDATE accounts SET balance = balance - 100 WHERE account_id = 1;
  UPDATE accounts SET balance = balance + 100 WHERE account_id = 2;
COMMIT;

-- Verify
SELECT * FROM accounts ORDER BY account_id;
